  1→import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
  2→import { Stage } from 'react-konva';
  3→import { useNavigate } from 'react-router-dom';
  4→import { useAuth } from '../../Context/useAuth';
  5→import { getUniversePosts, getUserData } from '../../../API/Api';
  6→import useUniverseCamera from './hooks/useUniverseCamera';
  7→import DeepSpaceLayer from './layers/DeepSpaceLayer';
  8→import MidGalaxyLayer from './layers/MidGalaxyLayer';
  9→import InteractiveLayer from './layers/InteractiveLayer';
 10→import { extractSnippet, userHomeCoords } from './utils/starUtils';
 11→import { handleClickProfile } from '../../../helpers/handleClicks';
 12→import styles from './Universe.module.css';
 13→
 14→const Universe = () => {
 15→    const navigate = useNavigate();
 16→    const { user } = useAuth();
 17→    const userId = user?.userData?.[0]?.id || null;
 18→
 19→    const debounceRef = useRef(null);
 20→    const [posts, setPosts] = useState(new Map());
 21→    const [selectedPost, setSelectedPost] = useState(null);
 22→    const [selectedGalaxy, setSelectedGalaxy] = useState(null);
 23→    const [galaxyProfile, setGalaxyProfile] = useState(null);
 24→    const [pulsingId, setPulsingId] = useState(null);
 25→    // null = still loading, true/false = resolved
 26→    const [hasOwnPosts, setHasOwnPosts] = useState(userId ? null : false);
 27→
 28→    const {
 29→        stageRef,
 30→        stageSize,
 31→        camera,
 32→        zoom,
 33→        isDragging,
 34→        centerWorld,
 35→        getLayerProps,
 36→        getViewportBounds,
 37→        stageEvents,
 38→        flyTo,
 39→        isFlying,
 40→    } = useUniverseCamera(userId, hasOwnPosts);
 41→
 42→    // Debounced fetch on camera/zoom change
 43→    useEffect(() => {
 44→        if (debounceRef.current) clearTimeout(debounceRef.current);
 45→
 46→        debounceRef.current = setTimeout(async () => {
 47→            const bounds = getViewportBounds();
 48→            try {
 49→                const result = await getUniversePosts(bounds.minX, bounds.maxX, bounds.minY, bounds.maxY, 200);
 50→                if (result?.data) {
 51→                    setPosts(prev => {
 52→                        const next = new Map(prev);
 53→                        for (const post of result.data) {
 54→                            next.set(post.id, post);
 55→                        }
 56→                        return next;
 57→                    });
 58→                    // Check if any returned posts belong to this user
 59→                    if (userId && hasOwnPosts === null) {
 60→                        const ownsAny = result.data.some(p => p.users?.id === userId);
 61→                        setHasOwnPosts(ownsAny);
 62→                    }
 63→                }
 64→            } catch (err) {
 65→                console.error('Failed to fetch universe posts:', err);
 66→            }
 67→        }, 400);
 68→
 69→        return () => {
 70→            if (debounceRef.current) clearTimeout(debounceRef.current);
 71→        };
 72→    }, [camera, zoom, getViewportBounds, userId, hasOwnPosts]);
 73→
 74→    const handleStarClick = useCallback((post) => {
 75→        if (isFlying.current) return;
 76→        setSelectedPost(post);
 77→        setSelectedGalaxy(null);
 78→        setGalaxyProfile(null);
 79→        flyTo(post.universe_x, post.universe_y, 1.2, () => {
 80→            setPulsingId(post.id);
 81→            setTimeout(() => setPulsingId(null), 700);
 82→        });
 83→    }, [flyTo, isFlying]);
 84→
 85→    const handleGalaxyClick = useCallback(async (galaxy) => {
 86→        if (isFlying.current) return;
 87→        setSelectedGalaxy(galaxy);
 88→        setSelectedPost(null);
 89→        setGalaxyProfile(null);
 90→
 91→        // Zoom into the galaxy
 92→        flyTo(galaxy.x, galaxy.y, 0.8);
 93→
 94→        try {
 95→            const data = await getUserData(galaxy.userId);
 96→            const profile = data?.userData?.[0] || null;
 97→            setGalaxyProfile(profile);
 98→        } catch (err) {
 99→            console.error('Failed to fetch galaxy profile:', err);
100→        }
101→    }, [flyTo, isFlying]);
102→
103→    const handleReadPost = useCallback(() => {
104→        if (!selectedPost) return;
105→        navigate(`/home/post/${selectedPost.id}`);
106→    }, [selectedPost, navigate]);
107→
108→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
109→    const showTitles = zoom > 0.5;
110→
111→    // Derive one label per unique user (galaxy)
112→    const galaxies = useMemo(() => {
113→        const seen = new Map();
114→        for (const post of postArray) {
115→            const uid = post.users?.id;
116→            if (!uid || seen.has(uid)) continue;
117→            const home = userHomeCoords(uid);
118→            seen.set(uid, {
119→                userId: uid,
120→                name: post.users?.name || 'Anonymous',
121→                x: home.x,
122→                y: home.y,
123→            });
124→        }
125→        return Array.from(seen.values());
126→    }, [postArray]);
127→
128→    return (
129→        <div className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}>
130→            <button className={styles.backButton} onClick={() => navigate('/home')}>
131→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
132→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
133→                </svg>
134→                Back
135→            </button>
136→
137→            <div className={styles.coordsLabel}>
138→                {centerWorld.x}, {centerWorld.y}
139→            </div>
140→
141→            <Stage
142→                ref={stageRef}
143→                width={stageSize.width}
144→                height={stageSize.height}
145→                {...stageEvents}
146→            >
147→                <DeepSpaceLayer layerProps={getLayerProps(0.1)} />
148→                <MidGalaxyLayer layerProps={getLayerProps(0.4)} />
149→                <InteractiveLayer
150→                    layerProps={getLayerProps(1.0)}
151→                    posts={postArray}
152→                    galaxies={galaxies}
153→                    zoom={zoom}
154→                    showTitles={showTitles}
155→                    pulsingId={pulsingId}
156→                    onStarClick={handleStarClick}
157→                    onGalaxyClick={handleGalaxyClick}
158→                />
159→            </Stage>
160→
161→            {selectedGalaxy && galaxyProfile && (
162→                <div className={styles.galaxyPreviewPanel}>
163→                    <button
164→                        className={styles.galaxyPreviewClose}
165→                        onClick={() => { setSelectedGalaxy(null); setGalaxyProfile(null); }}
166→                    >
167→                        &times;
168→                    </button>
169→                    <div
170→                        className={styles.galaxyPreviewBg}
171→                        style={galaxyProfile.background || {}}
172→                    />
173→                    <div className={styles.galaxyPreviewContent}>
174→                        <img
175→                            className={styles.galaxyPreviewAvatar}
176→                            src={galaxyProfile.image_url || '/assets/profile.jpg'}
177→                            alt=""
178→                        />
179→                        <div className={styles.galaxyPreviewHeading}>
180→                            This is {galaxyProfile.name || selectedGalaxy.name}'s galaxy
181→                        </div>
182→                        {galaxyProfile.bio && (
183→                            <div className={styles.galaxyPreviewBio}>{galaxyProfile.bio}</div>
184→                        )}
185→                        <button
186→                            className={styles.galaxyPreviewVisitBtn}
187→                            onClick={(e) => handleClickProfile(navigate)(e, userId, selectedGalaxy.userId)}
188→                        >
189→                            Visit Profile
190→                        </button>
191→                    </div>
192→                </div>
193→            )}
194→
195→            {selectedPost && (
196→                <div className={styles.previewPanel}>
197→                    <button
198→                        className={styles.previewClose}
199→                        onClick={() => setSelectedPost(null)}
200→                    >
201→                        &times;
202→                    </button>
203→                    <div className={styles.previewAuthor}>
204→                        <img
205→                            className={styles.previewAvatar}
206→                            src={selectedPost.users?.image_url || '/assets/profile.jpg'}
207→                            alt=""
208→                        />
209→                        <span className={styles.previewAuthorName}>
210→                            {selectedPost.users?.name || 'Anonymous'}
211→                        </span>
212→                    </div>
213→                    <div className={styles.previewTitle}>{selectedPost.title}</div>
214→                    <div className={styles.previewSnippet}>{extractSnippet(selectedPost)}</div>
215→                    <div className={styles.previewLikes}>
216→                        {Array.isArray(selectedPost.likes) && selectedPost.likes[0]?.count
217→                            ? `${selectedPost.likes[0].count} like${selectedPost.likes[0].count !== 1 ? 's' : ''}`
218→                            : '0 likes'}
219→                    </div>
220→                    <button className={styles.previewReadBtn} onClick={handleReadPost}>
221→                        Read
222→                    </button>
223→                </div>
224→            )}
225→        </div>
226→    );
227→};
228→
229→export default Universe;
