34→export const extractSnippet = (post) => {
35→    if (post.post_type === 'canvas' && post.canvas_doc?.snippets) {
36→        return post.canvas_doc.snippets
37→            .map(s => s?.text || '')
38→            .filter(Boolean)
39→            .join(' ')
40→            .slice(0, 200);
41→    }
42→    if (typeof post.content === 'string') {
43→        try {
44→            const parsed = JSON.parse(post.content);
45→            const extractText = (node) => {
46→                if (!node) return '';
47→                if (typeof node.text === 'string') return node.text;
48→                if (Array.isArray(node.children)) {
49→                    return node.children.map(extractText).join('');
50→                }
51→                return '';
52→            };
53→            return extractText(parsed.root || parsed).slice(0, 200);
54→        } catch {
55→            return post.content.slice(0, 200);
56→        }
57→    }
58→    return '';
59→};
