  87→    img_buffer = await sharp(file.buffer)
  88→    .webp({quality: 80})
  89→    .toBuffer();
  90→
  91→    const folderName = `user_id_${userId}`;
  92→    const fileName = `${Date.now()}_${crypto.randomUUID()}.webp`;
