 1→import { pipeline } from "@xenova/transformers";
 2→
 3→let embeddingPipelinePromise;
 4→
 5→const EMBEDDING_MODEL = 'Supabase/gte-small';
 6→const MAX_EMBEDDING_INPUT_CHARS = 6000;
 7→const CACHE_MAX_ENTRIES = 250;
 8→const CACHE_TTL_MS = 10 * 60 * 1000;
 9→const embeddingCache = new Map();
10→
11→const getEmbeddingPipeline = () => {
12→    if(!embeddingPipelinePromise){
13→        embeddingPipelinePromise = pipeline('feature-extraction', EMBEDDING_MODEL);
14→    }
15→    return embeddingPipelinePromise;
16→}
17→
18→const normalizeTextInput = (title = '', body = '') => {
19→    const merged = `${title ?? ''} ${body ?? ''}`
20→        .replace(/\s+/g, ' ')
21→        .trim();
22→
23→    if(!merged){
24→        return null;
25→    }
26→
27→    if(merged.length <= MAX_EMBEDDING_INPUT_CHARS){
28→        return merged;
29→    }
30→
31→    return merged.slice(0, MAX_EMBEDDING_INPUT_CHARS);
32→}
33→
34→const getCachedEmbedding = (text) => {
35→    const cached = embeddingCache.get(text);
36→    if(!cached){
37→        return null;
38→    }
39→
40→    if(Date.now() > cached.expiresAt){
41→        embeddingCache.delete(text);
42→        return null;
43→    }
44→
45→    return [...cached.embedding];
46→}
47→
48→const setCachedEmbedding = (text, embedding) => {
49→    if(embeddingCache.size >= CACHE_MAX_ENTRIES){
50→        const firstKey = embeddingCache.keys().next().value;
51→        if(firstKey){
52→            embeddingCache.delete(firstKey);
53→        }
54→    }
55→
56→    embeddingCache.set(text, {
57→        embedding: [...embedding],
58→        expiresAt: Date.now() + CACHE_TTL_MS
59→    });
60→}
61→
62→const GenerateEmbeddings = async(title = '', body = '') => {
63→    const normalizedText = normalizeTextInput(title, body);
64→    if(!normalizedText){
65→        return null;
66→    }
67→
68→    const cachedEmbedding = getCachedEmbedding(normalizedText);
69→    if(cachedEmbedding){
70→        return cachedEmbedding;
71→    }
72→
73→    const genereateEmbedding = await getEmbeddingPipeline();
74→    const output = await genereateEmbedding(normalizedText, {
75→        pooling: 'mean',
76→        normalize: true
77→    })
78→
79→    const embedding = Array.from(output.data);
80→    setCachedEmbedding(normalizedText, embedding);
81→
82→    return embedding;
83→}
84→
85→export default GenerateEmbeddings;
