 352→export const getJournalsService = async(limit, userId, before) => {
 353→    if(isNaN(limit) || limit > 20 || limit < 1){
 354→        console.error('limit should be intiger, not below 1 and higher than 20');
 355→        throw {status: 400, error: 'limit should be intiger, not below 1 and higher than 20'};
 356→    }
 357→
 358→    const parsedLimit = parseInt(limit);
 359→
 360→    let query = supabase
 361→    .from('journals')
 362→    .select(`
 363→        *, users(*),
 364→        like_count: likes(count),
 365→        comment_count: comments(count),
 366→        bookmark_count: bookmarks(count)
 367→        `)
 368→    .eq('privacy', 'public')
 369→    .order('created_at', {ascending: false})
 370→    .order('id', {ascending: false})
 371→    .limit(parsedLimit + 1);
 372→
 373→    if(before){
 374→        query = query.lt('created_at', before);
 375→    }
 376→
 377→    const {data, error} = await query;
 378→
 379→    if(error){
 380→        console.error('supabase error while fetching journals:', error.message);
 381→        throw{status: 500, error: 'supabase error while fetching journals'}
 382→    }
 383→
 384→    if(data.length === 0){
 385→        const journalData = {
 386→            data: [],
 387→            hasMore: false
 388→        }
 389→        return journalData
 390→    }
 391→
 392→    // If userId is provided, fetch personalization (likes/bookmarks)
 393→    // Otherwise return journals with has_liked/has_bookmarked defaulting to false
 394→    let userHasLikedSet = new Set();
 395→    let userHasBookmarkedSet = new Set();
 396→
 397→    if(userId){
 398→        const journalIds = data.map((journal) => journal.id);
 399→
 400→        const [userLikes, userBookmarks] = await Promise.all([
 401→            supabase
 402→            .from('likes')
 403→            .select('journal_id')
 404→            .in('journal_id', journalIds)
 405→            .eq('user_id', userId),
 406→
 407→            supabase
 408→            .from('bookmarks')
 409→            .select('journal_id')
 410→            .in('journal_id', journalIds)
 411→            .eq('user_id', userId)
 412→        ]);
 413→
 414→        const {data: userLikesResult, error: errorUserLikeResult} = userLikes;
 415→        const {data: userBookmarksResult, error: errorUserBookmarksResult} = userBookmarks;
