 417→        if(errorUserLikeResult || errorUserBookmarksResult) {
 418→            console.error('supabase error:', errorUserLikeResult?.message || errorUserBookmarksResult?.message);
 419→            throw {status: 500, error: 'supabase error on fetching user likes or user bookmarks'}
 420→        }
 421→
 422→        userHasLikedSet = new Set(userLikesResult?.map((j) => j.journal_id) || []);
 423→        userHasBookmarkedSet = new Set(userBookmarksResult?.map((j) => j.journal_id)|| []);
