1035→export const searchJournalsService = async(query, limit, userId) => {
1036→    const normalizedQuery = normalizeSearchQuery(query);
1037→    if(!normalizedQuery || normalizedQuery.length < SEARCH_QUERY_MIN_LENGTH){
1038→        throw {status: 400, error: `query should be at least ${SEARCH_QUERY_MIN_LENGTH} characters`};
1039→    }
1040→
1041→    if(isNaN(limit) || limit < 1 || limit > SEARCH_LIMIT_MAX){
1042→        throw {status: 400, error: `limit should be an integer between 1 and ${SEARCH_LIMIT_MAX}`};
1043→    }
1044→
1045→    const parsedLimit = parseInt(limit);
1046→    const fetchLimit = Math.min(parsedLimit * 3, 60);
1047→
1048→    const selectColumns = `
1049→        *,
1050→        users(*),
1051→        like_count: likes(count),
1052→        comment_count: comments(count),
1053→        bookmark_count: bookmarks(count)
1054→    `;
1055→
1056→    // Prefer semantic retrieval. If pgvector RPC is unavailable or errors,
1057→    // fallback to keyword search so endpoint still returns useful data.
1058→    try {
1059→        const queryEmbedding = await GenerateEmbeddings(normalizedQuery, '');
1060→
1061→        if(Array.isArray(queryEmbedding) && queryEmbedding.length > 0){
1062→            const {data: matches, error: matchError} = await supabase.rpc('match_public_journals', {
1063→                query_embedding: queryEmbedding,
1064→                match_count: fetchLimit,
1065→                similarity_threshold: 0.35
1066→            });
1067→
1068→            if(matchError){
1069→                console.error('semantic search rpc error:', matchError.message);
1070→            } else if(Array.isArray(matches) && matches.length > 0){
1071→                const matchIds = matches.map((row) => row.id);
1072→                const similarityMap = new Map(matches.map((row) => [row.id, row.similarity]));
1073→
1074→                const {data: journals, error: errorJournals} = await supabase
1075→                    .from('journals')
1076→                    .select(selectColumns)
1077→                    .in('id', matchIds)
1078→                    .eq('privacy', 'public');
1079→
1080→                if(errorJournals){
1081→                    console.error('supabase error while fetching semantic search journals:', errorJournals.message);
1082→                    throw {status: 500, error: 'supabase error while fetching semantic search journals'};
1083→                }
1084→
1085→                const journalById = new Map((journals || []).map((journal) => [journal.id, journal]));
1086→                const orderedSemantic = matchIds
1087→                    .map((id) => journalById.get(id))
1088→                    .filter(Boolean)
1089→                    .map((journal) => ({
1090→                        ...journal,
1091→                        similarity: similarityMap.get(journal.id) || null
1092→                    }));
1093→
1094→                const withInteraction = await attachUserInteractionFlags(orderedSemantic, userId);
1095→                const hasMore = withInteraction.length > parsedLimit;
1096→
1097→                return {
1098→                    data: hasMore ? withInteraction.slice(0, parsedLimit) : withInteraction,
1099→                    hasMore: hasMore,
1100→                    mode: 'semantic'
1101→                };
1102→            }
1103→        }
1104→    } catch (error) {
1105→        console.error('semantic embedding/search fallback error:', error?.message || error);
1106→    }
1107→
1108→    const escapedQuery = normalizedQuery.replace(/[%_]/g, (match) => `\\${match}`);
1109→
1110→    const [titleResult, contentResult] = await Promise.all([
1111→        supabase
1112→            .from('journals')
1113→            .select(selectColumns)
1114→            .eq('privacy', 'public')
1115→            .ilike('title', `%${escapedQuery}%`)
1116→            .order('created_at', {ascending: false})
1117→            .order('id', {ascending: false})
1118→            .limit(parsedLimit + 1),
1119→        supabase
1120→            .from('journals')
1121→            .select(selectColumns)
1122→            .eq('privacy', 'public')
1123→            .ilike('content', `%${escapedQuery}%`)
1124→            .order('created_at', {ascending: false})
1125→            .order('id', {ascending: false})
1126→            .limit(parsedLimit + 1)
1127→    ]);
1128→
1129→    if(titleResult.error || contentResult.error){
1130→        console.error('keyword search error:', titleResult.error?.message || contentResult.error?.message);
1131→        throw {status: 500, error: 'supabase error while searching journals'};
1132→    }
1133→
1134→    const keywordMap = new Map();
1135→    (titleResult.data || []).forEach((journal) => {
1136→        keywordMap.set(journal.id, journal);
1137→    });
1138→    (contentResult.data || []).forEach((journal) => {
1139→        if(!keywordMap.has(journal.id)){
1140→            keywordMap.set(journal.id, journal);
1141→        }
1142→    });
1143→
1144→    const keywordJournals = [...keywordMap.values()];
1145→
1146→    const withInteraction = await attachUserInteractionFlags(keywordJournals || [], userId);
1147→    const hasMore = withInteraction.length > parsedLimit;
1148→
1149→    return {
1150→        data: hasMore ? withInteraction.slice(0, parsedLimit) : withInteraction,
1151→        hasMore: hasMore,
1152→        mode: 'keyword'
1153→    };
1154→}
