  7→const GalaxyLabel = React.memo(({ x, y, name, zoom, onClick }) => {
  8→    // Inverse-scale so the label stays a constant screen size
  9→    const invZoom = 1 / zoom;
 10→    return (
 11→        <Group x={x} y={y} scaleX={invZoom} scaleY={invZoom}>
 12→            <Text
 13→                text={name}
 14→                fontSize={14}
 15→                fill="rgba(255,255,255,0.45)"
 16→                fontStyle="600"
 17→                fontFamily="inherit"
 18→                align="center"
 19→                width={200}
 20→                offsetX={100}
 21→                y={-24}
 22→                perfectDrawEnabled={false}
 23→                onMouseEnter={(e) => {
 24→                    e.target.fill('rgba(255,255,255,0.75)');
 25→                    const container = e.target.getStage().container();
 26→                    container.style.cursor = 'pointer';
 27→                }}
 28→                onMouseLeave={(e) => {
 29→                    e.target.fill('rgba(255,255,255,0.45)');
 30→                    const container = e.target.getStage().container();
 31→                    container.style.cursor = 'grab';
 32→                }}
 33→                onClick={onClick}
 34→                onTap={onClick}
 35→            />
 36→        </Group>
 37→    );
 38→});
 39→
 40→GalaxyLabel.displayName = 'GalaxyLabel';
 41→
 42→const InteractiveLayer = React.memo(({ layerProps, posts, galaxies, zoom, showTitles, pulsingId, onStarClick, onGalaxyClick }) => {
 43→    const galaxyVisuals = useMemo(() =>
 44→        galaxies?.map(g => ({
 45→            x: g.x,
 46→            y: g.y,
 47→            ...generateGalaxyData(g.userId),
 48→            color: getStarColor(g.userId),
 49→        })) || []
 50→    , [galaxies]);
 51→
 52→    return (
 53→        <Layer {...layerProps}>
 54→            {/* Spiral galaxy visuals (behind labels and stars) */}
 55→            <Shape
 56→                sceneFunc={(ctx) => { drawGalaxyVisuals(ctx, galaxyVisuals); }}
 57→                perfectDrawEnabled={false}
 58→                listening={false}
 59→            />
 60→            {/* Galaxy name labels (behind stars) */}
 61→            {galaxies?.map((g) => (
 62→                <GalaxyLabel
 63→                    key={g.userId}
 64→                    x={g.x}
 65→                    y={g.y}
 66→                    name={g.name}
 67→                    zoom={zoom}
 68→                    onClick={() => onGalaxyClick(g)}
 69→                />
 70→            ))}
 71→            {posts.map((post) => {
 72→                const postUserId = post.users?.id;
 73→                const color = getStarColor(postUserId);
 74→                const likeCount = Array.isArray(post.likes) && post.likes[0]?.count != null
 75→                    ? post.likes[0].count
 76→                    : 0;
 77→                const radius = getStarRadius(likeCount);
 78→
 79→                return (
 80→                    <StarGroup
 81→                        key={post.id}
 82→                        x={post.universe_x}
 83→                        y={post.universe_y}
 84→                        radius={radius}
 85→                        color={color}
 86→                        title={post.title}
 87→                        showTitle={showTitles}
 88→                        isPulsing={pulsingId === post.id}
 89→                        onClick={() => onStarClick(post)}
 90→                    />
 91→                );
 92→            })}
 93→        </Layer>
 94→    );
 95→});
 96→
 97→InteractiveLayer.displayName = 'InteractiveLayer';
 98→
 99→export default InteractiveLayer;
