 14→const Universe = () => {
 15→    const navigate = useNavigate();
 16→    const { user } = useAuth();
 17→    const userId = user?.userData?.[0]?.id || null;
 18→
 19→    const debounceRef = useRef(null);
 20→    const [posts, setPosts] = useState(new Map());
 21→    const [selectedPost, setSelectedPost] = useState(null);
 22→    const [selectedGalaxy, setSelectedGalaxy] = useState(null);
 23→    const [galaxyProfile, setGalaxyProfile] = useState(null);
 24→    const [pulsingId, setPulsingId] = useState(null);
 25→    // null = still loading, true/false = resolved
 26→    const [hasOwnPosts, setHasOwnPosts] = useState(userId ? null : false);
 27→
 28→    const {
 29→        stageRef,
 30→        stageSize,
 31→        camera,
 32→        zoom,
 33→        isDragging,
 34→        centerWorld,
 35→        getLayerProps,
 36→        getViewportBounds,
 37→        stageEvents,
 38→        flyTo,
 39→        isFlying,
 40→    } = useUniverseCamera(userId, hasOwnPosts);
 41→
 42→    // Debounced fetch on camera/zoom change
 43→    useEffect(() => {
 44→        if (debounceRef.current) clearTimeout(debounceRef.current);
 45→
 46→        debounceRef.current = setTimeout(async () => {
 47→            const bounds = getViewportBounds();
 48→            try {
 49→                const result = await getUniversePosts(bounds.minX, bounds.maxX, bounds.minY, bounds.maxY, 200);
 50→                if (result?.data) {
 51→                    setPosts(prev => {
 52→                        const next = new Map(prev);
 53→                        for (const post of result.data) {
 54→                            next.set(post.id, post);
 55→                        }
 56→                        return next;
 57→                    });
 58→                    // Check if any returned posts belong to this user
 59→                    if (userId && hasOwnPosts === null) {
 60→                        const ownsAny = result.data.some(p => p.users?.id === userId);
 61→                        setHasOwnPosts(ownsAny);
 62→                    }
 63→                }
 64→            } catch (err) {
 65→                console.error('Failed to fetch universe posts:', err);
 66→            }
 67→        }, 400);
 68→
 69→        return () => {
 70→            if (debounceRef.current) clearTimeout(debounceRef.current);
 71→        };
 72→    }, [camera, zoom, getViewportBounds, userId, hasOwnPosts]);
 73→
 74→    const handleStarClick = useCallback((post) => {
 75→        if (isFlying.current) return;
 76→        setSelectedPost(post);
 77→        setSelectedGalaxy(null);
 78→        setGalaxyProfile(null);
 79→        flyTo(post.universe_x, post.universe_y, 1.2, () => {
 80→            setPulsingId(post.id);
 81→            setTimeout(() => setPulsingId(null), 700);
 82→        });
 83→    }, [flyTo, isFlying]);
 84→
 85→    const handleGalaxyClick = useCallback(async (galaxy) => {
 86→        if (isFlying.current) return;
 87→        setSelectedGalaxy(galaxy);
 88→        setSelectedPost(null);
 89→        setGalaxyProfile(null);
 90→
 91→        // Zoom into the galaxy
 92→        flyTo(galaxy.x, galaxy.y, 0.8);
 93→
 94→        try {
 95→            const data = await getUserData(galaxy.userId);
 96→            const profile = data?.userData?.[0] || null;
 97→            setGalaxyProfile(profile);
 98→        } catch (err) {
 99→            console.error('Failed to fetch galaxy profile:', err);
100→        }
101→    }, [flyTo, isFlying]);
102→
103→    const handleReadPost = useCallback(() => {
104→        if (!selectedPost) return;
105→        navigate(`/home/post/${selectedPost.id}`);
106→    }, [selectedPost, navigate]);
107→
108→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
109→    const showTitles = zoom > 0.5;
110→
111→    // Derive one label per unique user (galaxy)
112→    const galaxies = useMemo(() => {
113→        const seen = new Map();
114→        for (const post of postArray) {
115→            const uid = post.users?.id;
116→            if (!uid || seen.has(uid)) continue;
117→            const home = userHomeCoords(uid);
118→            seen.set(uid, {
119→                userId: uid,
120→                name: post.users?.name || 'Anonymous',
121→                x: home.x,
122→                y: home.y,
