124→        }
125→        return Array.from(seen.values());
126→    }, [postArray]);
127→
128→    return (
129→        <div className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}>
130→            <button className={styles.backButton} onClick={() => navigate('/home')}>
131→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
132→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
133→                </svg>
134→                Back
135→            </button>
136→
137→            <div className={styles.coordsLabel}>
138→                {centerWorld.x}, {centerWorld.y}
139→            </div>
140→
141→            <Stage
142→                ref={stageRef}
143→                width={stageSize.width}
144→                height={stageSize.height}
145→                {...stageEvents}
146→            >
147→                <DeepSpaceLayer layerProps={getLayerProps(0.1)} />
148→                <MidGalaxyLayer layerProps={getLayerProps(0.4)} />
149→                <InteractiveLayer
150→                    layerProps={getLayerProps(1.0)}
151→                    posts={postArray}
152→                    galaxies={galaxies}
153→                    zoom={zoom}
154→                    showTitles={showTitles}
155→                    pulsingId={pulsingId}
156→                    onStarClick={handleStarClick}
157→                    onGalaxyClick={handleGalaxyClick}
158→                />
159→            </Stage>
160→
161→            {selectedGalaxy && galaxyProfile && (
162→                <div className={styles.galaxyPreviewPanel}>
163→                    <button
164→                        className={styles.galaxyPreviewClose}
165→                        onClick={() => { setSelectedGalaxy(null); setGalaxyProfile(null); }}
166→                    >
167→                        &times;
168→                    </button>
169→                    <div
170→                        className={styles.galaxyPreviewBg}
171→                        style={galaxyProfile.background || {}}
172→                    />
173→                    <div className={styles.galaxyPreviewContent}>
174→                        <img
175→                            className={styles.galaxyPreviewAvatar}
176→                            src={galaxyProfile.image_url || '/assets/profile.jpg'}
