 87→                        showTitle={showTitles}
 88→                        isPulsing={pulsingId === post.id}
 89→                        onClick={() => onStarClick(post)}
 90→                    />
 91→                );
 92→            })}
 93→        </Layer>
 94→    );
 95→});
 96→
 97→InteractiveLayer.displayName = 'InteractiveLayer';
