100→                onTap={onClick}
101→            />
102→            {showTitle && title && (
103→                <Text
104→                    text={title.length > 24 ? title.slice(0, 22) + '...' : title}
105→                    y={r * 2.2 + 4}
106→                    fontSize={10}
107→                    fill="rgba(255,255,255,0.6)"
108→                    align="center"
109→                    width={120}
110→                    offsetX={60}
