 1→import { STAR_COLORS } from './starUtils';
 2→
 3→// Mulberry32 — fast seeded 32-bit PRNG
 4→export const mulberry32 = (seed) => {
 5→    let s = seed | 0;
 6→    return () => {
 7→        s = (s + 0x6D2B79F5) | 0;
 8→        let t = Math.imul(s ^ (s >>> 15), 1 | s);
 9→        t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
10→        return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
11→    };
12→};
13→
14→const WORLD_SPAN = 100000;
15→const HALF_SPAN = WORLD_SPAN / 2;
16→
17→export const generateDeepSpaceStars = (count = 2000, seed = 42) => {
18→    const rng = mulberry32(seed);
19→    const stars = new Array(count);
20→    for (let i = 0; i < count; i++) {
21→        stars[i] = {
22→            x: rng() * WORLD_SPAN - HALF_SPAN,
23→            y: rng() * WORLD_SPAN - HALF_SPAN,
24→            radius: 0.5 + rng() * 1.5,
25→            opacity: 0.2 + rng() * 0.5,
26→        };
27→    }
28→    return stars;
29→};
30→
31→export const generateMidGalaxyStars = (count = 800, seed = 137) => {
32→    const rng = mulberry32(seed);
33→    const stars = new Array(count);
34→    for (let i = 0; i < count; i++) {
35→        const color = STAR_COLORS[Math.floor(rng() * STAR_COLORS.length)];
36→        stars[i] = {
37→            x: rng() * WORLD_SPAN - HALF_SPAN,
38→            y: rng() * WORLD_SPAN - HALF_SPAN,
39→            radius: 1 + rng() * 3,
40→            opacity: 0.3 + rng() * 0.5,
41→            color,
42→        };
43→    }
44→    return stars;
45→};
46→
47→export const generateNebulae = (count = 18, seed = 256) => {
48→    const rng = mulberry32(seed);
49→    const nebulae = new Array(count);
50→    for (let i = 0; i < count; i++) {
51→        nebulae[i] = {
52→            x: rng() * WORLD_SPAN - HALF_SPAN,
53→            y: rng() * WORLD_SPAN - HALF_SPAN,
54→            radius: 200 + rng() * 600,
55→            opacity: 0.03 + rng() * 0.06,
56→            color: STAR_COLORS[Math.floor(rng() * STAR_COLORS.length)],
57→        };
58→    }
59→    return nebulae;
60→};
