## 3. Server-Side Implementation

### 3.1 Galaxy Settle Service: `server/services/galaxySettleService.js`

This is the core algorithm. It runs as a batch job.

```javascript
// Function signatures and algorithm:

/**
 * Step 1: Recompute mean embeddings for all users with public posts.
 * Called periodically or when posts are created/deleted.
 */
async function recomputeAllCentroids()
// - SELECT DISTINCT user_id FROM journals WHERE privacy='public' AND embeddings IS NOT NULL
// - For each user: call compute_user_mean_embedding RPC
// - UPSERT into galaxy_centroids

/**
 * Step 2: Recompute pairwise similarity between all galaxy centroids.
 * Only for pairs with similarity >= 0.25 (below this, no visual effect).
 */
async function recomputeGalaxyEdges()
// - Fetch all centroids with mean_embedding IS NOT NULL
// - For each pair (i,j) where i<j:
//     cosine_sim = dot(a.mean_embedding, b.mean_embedding) 
//                  / (norm(a) * norm(b))
//     -- Embeddings are already normalized (gte-small + normalize:true), so just dot product
// - Filter to similarity >= 0.25
// - Batch UPSERT into galaxy_edges
// - DELETE edges that fell below threshold

/**
 * Step 3: Force-directed layout for galaxy centers.
 * Uses the hash-based positions as initial positions.
 * 
 * Algorithm: Barnes-Hut inspired N-body simulation
 * - Repulsion: all galaxies repel each other (inverse square, scaled by post_count)
 * - Attraction: galaxy_edges pull galaxies together proportional to similarity
 * - Boundaries: soft wall at [-25000, 25000]
 * - Cooling: temperature starts at 1.0, decays by 0.97 per iteration
 * - Convergence: 200 iterations or max displacement < 1.0
 */
async function settleGalaxyPositions()
// Parameters:
//   REPULSION_STRENGTH = 5000
//   ATTRACTION_STRENGTH = 200
//   DAMPING = 0.9
//   COOLING_RATE = 0.97
//   MAX_ITERATIONS = 200
//   MIN_DISPLACEMENT = 1.0
//   BOUNDARY = 25000
//
// Algorithm:
//   galaxies = fetch all from galaxy_centroids
//   for each galaxy: pos = {x: hash_x, y: hash_y} (initial from userHomeCoords)
//   temperature = 1.0
//   
//   for iter in 0..MAX_ITERATIONS:
//     forces = new Map()  // userId -> {fx, fy}
//     
//     // Repulsion: O(n^2) for now, sector-optimize later
//     for each pair (i, j):
//       dx = j.x - i.x, dy = j.y - i.y
//       dist = max(sqrt(dx*dx + dy*dy), 50)
//       force = REPULSION_STRENGTH * (i.post_count + j.post_count) / (dist * dist)
//       forces[i] -= force * direction
//       forces[j] += force * direction
//     
//     // Attraction: only along edges
//     for each edge (a, b, similarity):
//       dx = b.x - a.x, dy = b.y - a.y
//       dist = sqrt(dx*dx + dy*dy)
//       idealDist = 2000 * (1 - similarity)  // similar = closer
//       force = ATTRACTION_STRENGTH * (dist - idealDist) * similarity
//       forces[a] += force * direction
//       forces[b] -= force * direction
//     
//     // Apply forces with cooling
//     maxDisp = 0
//     for each galaxy:
//       displacement = clamp(force * temperature, maxSpeed)
//       galaxy.x += displacement.x * DAMPING
//       galaxy.y += displacement.y * DAMPING
//       galaxy.x = clamp(galaxy.x, -BOUNDARY, BOUNDARY)
//       galaxy.y = clamp(galaxy.y, -BOUNDARY, BOUNDARY)
//       maxDisp = max(maxDisp, |displacement|)
//     
//     temperature *= COOLING_RATE
//     if maxDisp < MIN_DISPLACEMENT: break
//   
//   // Write settled positions back to galaxy_centroids
//   batch UPDATE galaxy_centroids SET galaxy_x, galaxy_y

/**
 * Step 4: Settle individual stars within each galaxy.
 * Each star's position = galaxy_center + spiral_offset + gravity_pull
 * The gravity_pull is toward centroids of other galaxies this post is similar to.
 */
async function settleStarPositions()
// For each galaxy:
//   posts = fetch journals with user_id = galaxy.user_id, embeddings IS NOT NULL
//   edges = fetch galaxy_edges where user_a = user_id or user_b = user_id
//   neighboring_centroids = galaxy_centroids for edge partners
//
//   For each post:
//     base_pos = galaxy_center + spiral_offset(index)
//     
//     // Gravity B: pull toward similar galaxies
//     pull = {x: 0, y: 0}
//     For each neighboring centroid:
//       post_similarity = dot(post.embedding, neighbor.mean_embedding) 
//       if post_similarity > 0.5:
//         direction = normalize(neighbor_pos - base_pos)
//         strength = (post_similarity - 0.5) * 2 * STAR_PULL_MAX  // 0-80px
//         pull += direction * strength
//     
//     settled_x = base_pos.x + clamp(pull.x, -80, 80)
//     settled_y = base_pos.y + clamp(pull.y, -80, 80)
//   
//   Batch UPDATE journals SET settled_x, settled_y

/**
 * Master function: run full settle pipeline.
 */
async function runFullSettle()
// 1. recomputeAllCentroids()
// 2. recomputeGalaxyEdges()
// 3. settleGalaxyPositions()
// 4. settleStarPositions()
```

