### 3.3 Route Changes: `server/routes/routes.js`

**Modified endpoint**: `GET /universe/posts` (lines 144-171)

The endpoint needs to return additional data:

```javascript
router.get('/universe/posts', optionalAuth, async(req, res) => {
    const {minX, maxX, minY, maxY, limit} = req.query;
    const parsedLimit = Math.min(Math.max(parseInt(limit) || 200, 1), 500);

    if(!minX || !maxX || !minY || !maxY){
        return res.status(400).json({error: 'minX, maxX, minY, maxY are required'});
    }

    const fMinX = parseFloat(minX);
    const fMaxX = parseFloat(maxX);
    const fMinY = parseFloat(minY);
    const fMaxY = parseFloat(maxY);

    // Fetch posts - use settled_x/y with fallback to universe_x/y
    const {data: posts, error} = await supabase
        .from('journals')
        .select(`
            id, title, content, post_type, canvas_doc, created_at,
            universe_x, universe_y, settled_x, settled_y,
            users(id, name, image_url, badge),
            likes(count)
        `)
        .eq('privacy', 'public')
        .not('universe_x', 'is', null)
        .not('universe_y', 'is', null)
        // Query using COALESCE(settled_x, universe_x) is not directly 
        // supported via Supabase client; use .or() with ranges on both columns,
        // or use an RPC. See section 3.4 for the RPC approach.
        .limit(parsedLimit);

    // Fetch galaxy centroids in viewport
    const {data: centroids} = await supabase
        .from('galaxy_centroids')
        .select('user_id, galaxy_x, galaxy_y, post_count')
        .not('galaxy_x', 'is', null)
        .gte('galaxy_x', fMinX - 500)
        .lte('galaxy_x', fMaxX + 500)
        .gte('galaxy_y', fMinY - 500)
        .lte('galaxy_y', fMaxY + 500);

    // Fetch galaxy edges for visible galaxies
    const {data: edges} = await supabase.rpc('get_galaxy_edges_in_viewport', {
        vp_min_x: fMinX - 500,
        vp_max_x: fMaxX + 500,
        vp_min_y: fMinY - 500,
        vp_max_y: fMaxY + 500,
        min_similarity: 0.3
    });

    // Fetch similar post pairs for semantic bridges
    const postIds = (posts || []).map(p => p.id);
    let similarPairs = [];
    if(postIds.length > 1 && postIds.length <= 500){
        const {data: pairs} = await supabase.rpc('find_similar_post_pairs', {
            post_ids: postIds,
            threshold: 0.9,
            max_pairs: 50
        });
        similarPairs = pairs || [];
    }

    return res.status(200).json({
        data: posts || [],
        centroids: centroids || [],
        edges: edges || [],
        similarPairs
    });
});
```

### 3.4 Viewport Query RPC (handles settled/fallback coordinates)

Because the Supabase JS client cannot easily do `COALESCE(settled_x, universe_x) BETWEEN ...`, create an RPC:

```sql
create or replace function public.get_universe_posts_viewport(
    vp_min_x float, vp_max_x float,
    vp_min_y float, vp_max_y float,
    max_count int default 200
)
returns table (
    id bigint,
    title text,
    content text,
    post_type text,
    canvas_doc jsonb,
    created_at timestamptz,
    display_x float,
    display_y float,
    user_id uuid,
    user_name text,
    user_image_url text,
    user_badge text,
    like_count bigint
)
language sql
stable
as $$
    select
        j.id,
        j.title,
        j.content,
        j.post_type,
        j.canvas_doc,
        j.created_at,
        coalesce(j.settled_x, j.universe_x) as display_x,
        coalesce(j.settled_y, j.universe_y) as display_y,
        u.id as user_id,
        u.name as user_name,
        u.image_url as user_image_url,
        u.badge as user_badge,
        coalesce(lc.cnt, 0) as like_count
    from public.journals j
    left join public.users u on u.id = j.user_id
    left join lateral (
        select count(*) as cnt from public.likes where journal_id = j.id
    ) lc on true
    where j.privacy = 'public'
      and coalesce(j.settled_x, j.universe_x) between vp_min_x and vp_max_x
      and coalesce(j.settled_y, j.universe_y) between vp_min_y and vp_max_y
    order by j.created_at desc
    limit greatest(max_count, 1);
$$;
```

