### 4.4 Semantic Bridges: Updated InteractiveLayer.jsx

Add a new `<Shape>` element that draws faint glowing lines between similar post pairs:

```javascript
// New prop: similarPairs, posts (already available)
// Inside InteractiveLayer:

const bridgeData = useMemo(() => {
    if(!similarPairs || similarPairs.length === 0) return [];
    const postMap = new Map(posts.map(p => [p.id, p]));
    return similarPairs
        .map(({post_a, post_b, similarity}) => {
            const a = postMap.get(post_a);
            const b = postMap.get(post_b);
            if(!a || !b) return null;
            return {
                ax: a.display_x ?? a.settled_x ?? a.universe_x,
                ay: a.display_y ?? a.settled_y ?? a.universe_y,
                bx: b.display_x ?? b.settled_x ?? b.universe_x,
                by: b.display_y ?? b.settled_y ?? b.universe_y,
                similarity
            };
        })
        .filter(Boolean);
}, [similarPairs, posts]);

// In the JSX, after galaxy visuals Shape and before stars:
<Shape
    sceneFunc={(ctx) => {
        for(const bridge of bridgeData) {
            const opacity = 0.1 * ((bridge.similarity - 0.9) / 0.1);
            // clamp opacity to [0.02, 0.12]
            const alpha = Math.max(0.02, Math.min(0.12, opacity));
            ctx.strokeStyle = `rgba(150, 200, 255, ${alpha})`;
            ctx.lineWidth = 0.8;
            ctx.shadowColor = 'rgba(150, 200, 255, 0.3)';
            ctx.shadowBlur = 4;
            const mx = (bridge.ax + bridge.bx) / 2;
            const my = (bridge.ay + bridge.by) / 2;
            // Slight perpendicular offset for arc
            const dx = bridge.bx - bridge.ax;
            const dy = bridge.by - bridge.ay;
            const dist = Math.sqrt(dx*dx + dy*dy) || 1;
            const perpX = -dy / dist * dist * 0.05;
            const perpY = dx / dist * dist * 0.05;
            ctx.beginPath();
            ctx.moveTo(bridge.ax, bridge.ay);
            ctx.quadraticCurveTo(mx + perpX, my + perpY, bridge.bx, bridge.by);
            ctx.stroke();
            ctx.shadowBlur = 0;
        }
    }}
    perfectDrawEnabled={false}
    listening={false}
/>
```

